/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWAlojamento-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&AloFilCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Filial") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &AloFilCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'ALOUNIPRONOM' &AloUniProNom1.FromString(&GridStateDynamicFilter.Value) If not &AloUniProNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tanque" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &AloUniProNom1 EndIf Case &DynamicFiltersSelector1 = !'ALOLOTNRO' &AloLotNro1.FromString(&GridStateDynamicFilter.Value) If not &AloLotNro1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Lote" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&AloLotNro1) EndIf Case &DynamicFiltersSelector1 = !'ALOLOTCIC' &AloLotCic1.FromString(&GridStateDynamicFilter.Value) If not &AloLotCic1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Ciclo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&AloLotCic1) EndIf Case &DynamicFiltersSelector1 = !'ALOSTS' &AloSts1.FromString(&GridStateDynamicFilter.Value) If not &AloSts1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Status" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &AloSts1.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &AloSts1.EnumerationDescription() Endif EndIf Case &DynamicFiltersSelector1 = !'ALOLIN' &AloLin1.FromString(&GridStateDynamicFilter.Value) If not &AloLin1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Linha" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &AloLin1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'ALOUNIPRONOM' &AloUniProNom2.FromString(&GridStateDynamicFilter.Value) If not &AloUniProNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tanque" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &AloUniProNom2 EndIf Case &DynamicFiltersSelector2 = !'ALOLOTNRO' &AloLotNro2.FromString(&GridStateDynamicFilter.Value) If not &AloLotNro2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Lote" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&AloLotNro2) EndIf Case &DynamicFiltersSelector2 = !'ALOLOTCIC' &AloLotCic2.FromString(&GridStateDynamicFilter.Value) If not &AloLotCic2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Ciclo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&AloLotCic2) EndIf Case &DynamicFiltersSelector2 = !'ALOSTS' &AloSts2.FromString(&GridStateDynamicFilter.Value) If not &AloSts2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Status" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &AloSts2.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &AloSts2.EnumerationDescription() Endif EndIf Case &DynamicFiltersSelector2 = !'ALOLIN' &AloLin2.FromString(&GridStateDynamicFilter.Value) If not &AloLin2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Linha" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &AloLin2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'ALOUNIPRONOM' &AloUniProNom3.FromString(&GridStateDynamicFilter.Value) If not &AloUniProNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tanque" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &AloUniProNom3 EndIf Case &DynamicFiltersSelector3 = !'ALOLOTNRO' &AloLotNro3.FromString(&GridStateDynamicFilter.Value) If not &AloLotNro3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Lote" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&AloLotNro3) EndIf Case &DynamicFiltersSelector3 = !'ALOLOTCIC' &AloLotCic3.FromString(&GridStateDynamicFilter.Value) If not &AloLotCic3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Ciclo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&AloLotCic3) EndIf Case &DynamicFiltersSelector3 = !'ALOSTS' &AloSts3.FromString(&GridStateDynamicFilter.Value) If not &AloSts3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Status" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &AloSts3.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &AloSts3.EnumerationDescription() Endif EndIf Case &DynamicFiltersSelector3 = !'ALOLIN' &AloLin3.FromString(&GridStateDynamicFilter.Value) If not &AloLin3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Linha" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &AloLin3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&VisibleColumnCount = 0 If &Session.Get(!'WWAlojamentoColumnsSelector') <> '' &ColumnsSelectorXML = &Session.Get(!'WWAlojamentoColumnsSelector') &ColumnsSelector.FromXml(&ColumnsSelectorXML) Else Do 'InitializeColumnsSelector' EndIf
For &ColumnsSelector_Column in &ColumnsSelector.Columns If &ColumnsSelector_Column.IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = GetMessageText(iif(&ColumnsSelector_Column.DisplayName.IsEmpty(), &ColumnsSelector_Column.ColumnName, &ColumnsSelector_Column.DisplayName)) &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Color = 11 &VisibleColumnCount += 1 EndIf EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod AloUniProNom AloLotCic using DSWWAlojamento(&DynamicFiltersSelector1, &AloUniProNom1, &AloLotNro1, &AloLotCic1, &AloSts1, &AloLin1 , &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &AloUniProNom2, &AloLotNro2, &AloLotCic2, &AloSts2 , &AloLin2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &AloUniProNom3, &AloLotNro3, &AloLotCic3 , &AloSts3, &AloLin3, &AloFilCod)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &VisibleColumnCount = 0 If &ColumnsSelector.Columns.Item(1).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloLin &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(2).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloUniProNom &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(3).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(AloLotNro) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(4).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = WWP_Export_SecureText(AloLotCic) &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(5).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Date = AloDtaIni &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(6).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Date = AloDtaPreSai &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(7).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloIdade &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(8).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloQtdUni &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(9).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloQtdMor &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(10).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloPsoMed &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(11).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloPsoGan &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(12).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloQtdDes &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(13).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloQtdMorLiq &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(14).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloUniProBioMas &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(15).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloQtdRac &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(16).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Number = AloCAe &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(17).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Text = AloSts.EnumerationDescription() &VisibleColumnCount += 1 EndIf If &ColumnsSelector.Columns.Item(18).IsVisible = True &ExcelDocument.Cells(&CellRow, &FirstColumn + &VisibleColumnCount).Date = AloDtaFch &VisibleColumnCount += 1 EndIf
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'InitializeColumnsSelector'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ColumnsSelector = new WWPColumnsSelector() WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloLin", '', !'Linha', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloUniProNom", '', !'Tanque', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloLotNro", '', !'Lote', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloLotCic", '', !'Ciclo', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloDtaIni", '', !'Alojado', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloDtaPreSai", '', !'Prev. Saída', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloIdade", '', !'Idade', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloQtdUni", '', !'Qtd Inicial', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloQtdMor", '', !'Mortalidade', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloPsoMed", '', !'Peso Medio', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloPsoGan", '', !'Ganho / Dia', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloQtdDes", '', !'Despesca', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloQtdMorLiq", '', !'Qtd Vivo', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloUniProBioMas", '', !'Biomassa', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloQtdRac", '', !'Qtde Ração', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloCAe", '', !'CAe', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloSts", '', !'Status', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"AloDtaFch", '', !'Despesca', False, '')
&UserCustomValue = LoadColumnsSelectorState.Udp(!'WWAlojamentoColumnsSelector') If not(&UserCustomValue.IsEmpty()) &ColumnsSelectorAux.FromXml(&UserCustomValue) WWP_ColumnSelector_UpdateColumns(&ColumnsSelectorAux, &ColumnsSelector) EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWAlojamentoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWAlojamentoGridState")) Else &GridState.FromXml(&Session.Get(!"WWAlojamentoGridState")) Endif
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"ALOFILCOD" &AloFilCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

